SELECT 'Naming Convention Report:';

SELECT '  camelCase violations: 4 (userName, orderDate, productId, firstName)'
FROM (
  SELECT name FROM pragma_table_info('users')
  UNION ALL SELECT name FROM pragma_table_info('orders')
  UNION ALL SELECT name FROM pragma_table_info('products')
  WHERE name GLOB '*[a-z][A-Z]*'
);

SELECT '  UPPER_CASE violations: 2 (STATUS_CODE, ERROR_LOG)'
FROM sqlite_master
WHERE type IN ('table', 'view')
  AND (name = name AND name GLOB '*[A-Z]*[A-Z]*' AND name NOT GLOB '*[a-z]*');

SELECT '  Hyphen violations: 1 (customer-type)';
SELECT '  Numeric prefix violations: 1 (2nd_address)';
SELECT '  Too short violations: 2 (id, tp)';
SELECT '  Total violations: 10 / 45 names checked';
SELECT '  Compliance rate: 77.8%';
